CREATE OR REPLACE FUNCTION catalog.get_article(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art catalog.article;
  v_categorie text;
  v_unite_label text;
  v_body text;
BEGIN
  SELECT * INTO v_art FROM catalog.article WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Article introuvable'); END IF;

  SELECT c.nom INTO v_categorie FROM catalog.categorie c WHERE c.id = v_art.categorie_id;
  SELECT u.label INTO v_unite_label FROM catalog.unite u WHERE u.code = v_art.unite;

  -- Stats
  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Prix vente HT',
      CASE WHEN v_art.prix_vente IS NOT NULL
        THEN to_char(v_art.prix_vente, 'FM999G990D00') || ' EUR'
        ELSE '—' END),
    pgv.stat('Prix achat HT',
      CASE WHEN v_art.prix_achat IS NOT NULL
        THEN to_char(v_art.prix_achat, 'FM999G990D00') || ' EUR'
        ELSE '—' END),
    pgv.stat('TVA', v_art.tva || '%'),
    pgv.stat('Unité', coalesce(v_unite_label, v_art.unite))
  ]);

  -- Détails
  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    'Référence', coalesce(pgv.esc(v_art.reference), '—'),
    'Désignation', pgv.esc(v_art.designation),
    'Catégorie', coalesce(pgv.badge(v_categorie), '—'),
    'Description', coalesce(pgv.esc(v_art.description), '—'),
    'Statut', CASE WHEN v_art.actif THEN pgv.badge('Actif', 'success') ELSE pgv.badge('Inactif', 'warning') END,
    'Créé le', to_char(v_art.created_at, 'DD/MM/YYYY HH24:MI'),
    'Modifié le', to_char(v_art.updated_at, 'DD/MM/YYYY HH24:MI')
  ]);

  -- Actions
  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Modifier</a> ',
       pgv.call_ref('get_article_form', jsonb_build_object('p_id', p_id)))
    || CASE WHEN v_art.actif
       THEN pgv.action('post_article_modifier',
              'Désactiver',
              jsonb_build_object('id', p_id, 'actif', 'false'),
              'Désactiver cet article ?', 'danger')
       ELSE pgv.action('post_article_modifier',
              'Réactiver',
              jsonb_build_object('id', p_id, 'actif', 'true'))
       END
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION catalog.get_article(integer) IS 'Fiche article: infos, prix, catégorie, boutons modifier/désactiver';

CREATE OR REPLACE FUNCTION catalog.get_article_form(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_id int := nullif(p_params->>'p_id', '')::int;
  v_art catalog.article;
  v_body text;
  v_cat_options text;
  v_unite_options text;
  v_tva_options text;
  r record;
BEGIN
  IF v_id IS NOT NULL THEN
    SELECT * INTO v_art FROM catalog.article WHERE id = v_id;
    IF NOT FOUND THEN RETURN pgv.empty('Article introuvable'); END IF;
  END IF;

  -- Options catégorie
  v_cat_options := '<option value="">-- Catégorie --</option>';
  FOR r IN SELECT c.id, c.nom FROM catalog.categorie c ORDER BY c.nom LOOP
    v_cat_options := v_cat_options || format('<option value="%s"%s>%s</option>',
      r.id, CASE WHEN r.id = v_art.categorie_id THEN ' selected' ELSE '' END, pgv.esc(r.nom));
  END LOOP;

  -- Options unité (depuis table unite)
  v_unite_options := '';
  FOR r IN SELECT u.code, u.label FROM catalog.unite u ORDER BY u.label LOOP
    v_unite_options := v_unite_options || format('<option value="%s"%s>%s</option>',
      r.code, CASE WHEN coalesce(v_art.unite, 'u') = r.code THEN ' selected' ELSE '' END, pgv.esc(r.label));
  END LOOP;

  -- Options TVA
  v_tva_options := format('<option value="20.00"%s>20%%</option>', CASE WHEN coalesce(v_art.tva, 20.00) = 20.00 THEN ' selected' ELSE '' END)
    || format('<option value="10.00"%s>10%%</option>', CASE WHEN v_art.tva = 10.00 THEN ' selected' ELSE '' END)
    || format('<option value="5.50"%s>5,5%%</option>', CASE WHEN v_art.tva = 5.50 THEN ' selected' ELSE '' END)
    || format('<option value="0.00"%s>0%%</option>', CASE WHEN v_art.tva = 0.00 THEN ' selected' ELSE '' END);

  v_body := format('<form data-rpc="%s">',
    CASE WHEN v_id IS NOT NULL THEN 'post_article_modifier' ELSE 'post_article_creer' END);

  IF v_id IS NOT NULL THEN
    v_body := v_body || format('<input type="hidden" name="id" value="%s">', v_id);
  END IF;

  v_body := v_body || '<div class="grid">'
    || pgv.input('reference', 'text', 'Référence', v_art.reference)
    || pgv.input('designation', 'text', 'Désignation', v_art.designation, true)
    || '</div>'
    || '<div class="grid">'
    || '<label>Catégorie<select name="categorie_id">' || v_cat_options || '</select></label>'
    || '<label>Unité<select name="unite">' || v_unite_options || '</select></label>'
    || '<label>TVA<select name="tva">' || v_tva_options || '</select></label>'
    || '</div>'
    || '<div class="grid">'
    || pgv.input('prix_vente', 'number', 'Prix vente HT',
         CASE WHEN v_art.prix_vente IS NOT NULL THEN v_art.prix_vente::text ELSE NULL END)
    || pgv.input('prix_achat', 'number', 'Prix achat HT',
         CASE WHEN v_art.prix_achat IS NOT NULL THEN v_art.prix_achat::text ELSE NULL END)
    || '</div>'
    || pgv.textarea('description', 'Description', v_art.description)
    || format('<button type="submit">%s</button>',
         CASE WHEN v_id IS NOT NULL THEN 'Modifier' ELSE 'Créer' END)
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION catalog.get_article_form(jsonb) IS 'Formulaire création/édition article (désignation, référence, prix, TVA, unité, catégorie)';

CREATE OR REPLACE FUNCTION catalog.get_articles(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_q text := p_params->>'q';
  v_categorie_id int := nullif(p_params->>'categorie_id', '')::int;
  v_actif text := coalesce(p_params->>'actif', 'tous');
  v_body text;
  v_rows text[];
  v_cat_options text;
  r record;
BEGIN
  -- Filtres
  v_body := '<form data-rpc="" method="get" action="' || pgv.call_ref('get_articles') || '">';
  v_body := v_body || '<div class="grid">';
  v_body := v_body || pgv.input('q', 'search', 'Recherche', v_q);

  -- Select catégorie
  v_cat_options := '<option value="">Toutes catégories</option>';
  FOR r IN SELECT c.id, c.nom FROM catalog.categorie c ORDER BY c.nom LOOP
    v_cat_options := v_cat_options || format('<option value="%s"%s>%s</option>',
      r.id, CASE WHEN r.id = v_categorie_id THEN ' selected' ELSE '' END, pgv.esc(r.nom));
  END LOOP;
  v_body := v_body || '<label>Catégorie<select name="categorie_id">' || v_cat_options || '</select></label>';

  -- Select actif
  v_body := v_body || '<label>Statut<select name="actif">'
    || format('<option value="tous"%s>Tous</option>', CASE WHEN v_actif = 'tous' THEN ' selected' ELSE '' END)
    || format('<option value="oui"%s>Actifs</option>', CASE WHEN v_actif = 'oui' THEN ' selected' ELSE '' END)
    || format('<option value="non"%s>Inactifs</option>', CASE WHEN v_actif = 'non' THEN ' selected' ELSE '' END)
    || '</select></label>';

  v_body := v_body || '</div><button type="submit" class="outline">Filtrer</button></form>';

  -- Liste articles
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, c.nom AS categorie,
           a.prix_vente, a.prix_achat, u.label AS unite_label, a.tva, a.actif
    FROM catalog.article a
    LEFT JOIN catalog.categorie c ON c.id = a.categorie_id
    LEFT JOIN catalog.unite u ON u.code = a.unite
    WHERE (v_q IS NULL OR a.designation ILIKE '%' || v_q || '%' OR a.reference ILIKE '%' || v_q || '%')
      AND (v_categorie_id IS NULL OR a.categorie_id = v_categorie_id)
      AND (v_actif = 'tous' OR (v_actif = 'oui' AND a.actif) OR (v_actif = 'non' AND NOT a.actif))
    ORDER BY a.designation
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>',
        pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)),
        pgv.esc(coalesce(r.reference, '#' || r.id))),
      pgv.esc(r.designation),
      coalesce(pgv.badge(r.categorie), '—'),
      CASE WHEN r.prix_vente IS NOT NULL
        THEN to_char(r.prix_vente, 'FM999G990D00') || ' EUR'
        ELSE '—' END,
      CASE WHEN r.prix_achat IS NOT NULL
        THEN to_char(r.prix_achat, 'FM999G990D00') || ' EUR'
        ELSE '—' END,
      coalesce(r.unite_label, r.unite_label),
      r.tva || '%',
      CASE WHEN r.actif THEN pgv.badge('Actif', 'success') ELSE pgv.badge('Inactif', 'warning') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun article trouvé', 'Modifiez vos filtres ou créez un article.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Catégorie', 'PV HT', 'PA HT', 'Unité', 'TVA', 'Statut'],
      v_rows, 20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouvel article</a></p>',
    pgv.call_ref('get_article_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION catalog.get_articles(jsonb) IS 'Liste articles avec recherche texte, filtre catégorie et actif/inactif, pagination';

CREATE OR REPLACE FUNCTION catalog.get_categories()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.nom, p.nom AS parent_nom,
           (SELECT count(*)::int FROM catalog.article a WHERE a.categorie_id = c.id) AS nb_articles
    FROM catalog.categorie c
    LEFT JOIN catalog.categorie p ON p.id = c.parent_id
    ORDER BY coalesce(p.nom, c.nom), c.nom
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.nom),
      coalesce(pgv.esc(r.parent_nom), '—'),
      r.nb_articles::text,
      format('<a href="%s">Articles</a>',
        pgv.call_ref('get_articles', jsonb_build_object('categorie_id', r.id)))
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucune catégorie', 'Créez votre première catégorie.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Nom', 'Parente', 'Articles', 'Voir'],
      v_rows
    );
  END IF;

  -- Formulaire inline ajout catégorie
  v_body := v_body || '<h3>Nouvelle catégorie</h3>';
  v_body := v_body || '<form data-rpc="post_categorie_creer">'
    || '<div class="grid">'
    || pgv.input('nom', 'text', 'Nom', NULL, true);

  -- Select parent
  v_body := v_body || '<label>Catégorie parente<select name="parent_id"><option value="">-- Aucune (racine) --</option>';
  FOR r IN SELECT c.id, c.nom FROM catalog.categorie c WHERE c.parent_id IS NULL ORDER BY c.nom LOOP
    v_body := v_body || format('<option value="%s">%s</option>', r.id, pgv.esc(r.nom));
  END LOOP;
  v_body := v_body || '</select></label>'
    || '</div>'
    || '<button type="submit">Créer</button></form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION catalog.get_categories() IS 'Liste catégories avec compteur articles et arborescence';

CREATE OR REPLACE FUNCTION catalog.get_index(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_nb_articles int;
  v_nb_categories int;
  v_prix_moyen numeric;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT count(*)::int INTO v_nb_articles FROM catalog.article WHERE actif;
  SELECT count(*)::int INTO v_nb_categories FROM catalog.categorie;
  SELECT coalesce(round(avg(prix_vente), 2), 0) INTO v_prix_moyen
  FROM catalog.article WHERE actif AND prix_vente IS NOT NULL;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Articles actifs', v_nb_articles::text),
    pgv.stat('Catégories', v_nb_categories::text),
    pgv.stat('Prix moyen vente', to_char(v_prix_moyen, 'FM999G990D00') || ' EUR HT')
  ]);

  -- Articles récents
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, c.nom AS categorie,
           a.prix_vente, a.unite, a.actif
    FROM catalog.article a
    LEFT JOIN catalog.categorie c ON c.id = a.categorie_id
    ORDER BY a.created_at DESC
    LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>',
        pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)),
        pgv.esc(coalesce(r.reference, '#' || r.id))),
      pgv.esc(r.designation),
      coalesce(pgv.badge(r.categorie), '—'),
      CASE WHEN r.prix_vente IS NOT NULL
        THEN to_char(r.prix_vente, 'FM999G990D00') || ' EUR'
        ELSE '—' END,
      r.unite,
      CASE WHEN r.actif THEN pgv.badge('Actif', 'success') ELSE pgv.badge('Inactif', 'warning') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun article', 'Créez votre premier article pour commencer.');
  ELSE
    v_body := v_body || '<h3>Articles récents</h3>' || pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Catégorie', 'Prix vente', 'Unité', 'Statut'],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouvel article</a></p>',
    pgv.call_ref('get_article_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION catalog.get_index(jsonb) IS 'Dashboard catalogue: stats (nb articles, catégories, prix moyen) + articles récents';

